package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

class CSVFormatTest {

    @Test
    void testWithIgnoreHeaderCase_noArg() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat modified = original.withIgnoreHeaderCase();

        assertNotNull(modified);
        assertTrue(modified.getIgnoreHeaderCase());
        // Original instance should remain unchanged
        assertFalse(original.getIgnoreHeaderCase());
        // The modified instance should be different from the original
        assertNotSame(original, modified);
    }

    @Test
    void testWithIgnoreHeaderCase_boolean_true() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;

        Method withIgnoreHeaderCaseBool = CSVFormat.class.getMethod("withIgnoreHeaderCase", boolean.class);

        CSVFormat modified = (CSVFormat) withIgnoreHeaderCaseBool.invoke(original, true);

        assertNotNull(modified);
        assertTrue(modified.getIgnoreHeaderCase());
        assertFalse(original.getIgnoreHeaderCase());
        assertNotSame(original, modified);
    }

    @Test
    void testWithIgnoreHeaderCase_boolean_false() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT.withIgnoreHeaderCase(true);

        Method withIgnoreHeaderCaseBool = CSVFormat.class.getMethod("withIgnoreHeaderCase", boolean.class);

        CSVFormat modified = (CSVFormat) withIgnoreHeaderCaseBool.invoke(original, false);

        assertNotNull(modified);
        assertFalse(modified.getIgnoreHeaderCase());
        assertTrue(original.getIgnoreHeaderCase());
        assertNotSame(original, modified);
    }
}
